const execution = $input.first().json;

// The error trigger provides execution context
const workflowId = execution.workflow?.id || 'unknown';
const workflowName = execution.workflow?.name || 'unknown';
const executionId = execution.execution?.id || 'unknown';
const executionMode = execution.execution?.mode || 'production';

// Extract error details from the last node that failed
let failedNode = 'unknown';
let errorMessage = 'Unknown error';
let errorStack = '';
let inputData = {};

try {
  const lastNode = execution.execution?.lastNodeExecuted || '';
  failedNode = lastNode;

  // Try to get error from execution data
  if (execution.execution?.error) {
    const err = execution.execution.error;
    errorMessage = err.message || err.description || JSON.stringify(err);
    errorStack = err.stack || '';
  }

  // Try to get input data from the failed node
  const runData = execution.execution?.data?.resultData?.runData;
  if (runData && runData[lastNode]) {
    const nodeData = runData[lastNode];
    const lastRun = nodeData[nodeData.length - 1];
    if (lastRun && lastRun.error) {
      errorMessage = lastRun.error.message || errorMessage;
      errorStack = lastRun.error.stack || errorStack;
    }
    // Capture input data for debugging
    if (lastRun && lastRun.inputData) {
      inputData = { keys: Object.keys(lastRun.inputData) };
    }
  }
} catch (e) {
  // If parsing fails, use what we have
  errorMessage = errorMessage || `Parse error: ${e.message}`;
}

return [{
  json: {
    workflow_id: workflowId,
    workflow_name: workflowName,
    execution_id: executionId,
    failed_node: failedNode,
    error_message: errorMessage.slice(0, 2000),
    error_stack: errorStack.slice(0, 5000),
    execution_mode: executionMode,
    input_data: JSON.stringify(inputData)
  }
}];
